def solve(grid: Array[Array[Long]], x: Long, y: Long, k: Long): Array[Array[Long]] = {
  val newGrid = grid.map(_.clone).toArray
  val submatrixRows = (x until x + k).map { row => grid(row).slice(y.toInt, y.toInt + k) }
  val reversedSubmatrix = submatrixRows.reverse
  for (i <- 0 until k) {
    val originalRow = newGrid(x + i)
    val newRow = reversedSubmatrix(i)
    val before = originalRow.take(y.toInt)
    val after = originalRow.drop(y.toInt + k)
    val combined = before ++ newRow ++ after
    newGrid(x + i) = combined
  }
  newGrid
}
